Here's how to test `DataFetcher` with modern MSTest patterns:

```csharp
[TestClass]
public sealed class DataFetcherTests
{
    private readonly TestContext _testContext;
    private readonly MockHttpMessageHandler _handler;
    private readonly DataFetcher _fetcher;

    public DataFetcherTests(TestContext testContext)
    {
        _testContext = testContext;
        _handler = new MockHttpMessageHandler();
        _fetcher = new DataFetcher(new HttpClient(_handler));
    }

    [TestMethod]
    public async Task FetchAsync_SuccessResponse_ReturnsContent()
    {
        _handler.ResponseContent = "hello world";
        _handler.StatusCode = HttpStatusCode.OK;

        var result = await _fetcher.FetchAsync("https://example.com");

        Assert.AreEqual("hello world", result);
    }

    [TestMethod]
    public async Task FetchAsync_NotFound_ThrowsHttpRequestException()
    {
        _handler.StatusCode = HttpStatusCode.NotFound;

        await Assert.ThrowsExactlyAsync<HttpRequestException>(
            async () => await _fetcher.FetchAsync("https://example.com"));
    }

    [TestMethod]
    [Timeout(5000)] // fail-safe: test fails if it hangs
    public async Task FetchAsync_RespectsTimeout()
    {
        _handler.ResponseContent = "ok";
        _handler.StatusCode = HttpStatusCode.OK;

        // Pass TestContext.CancellationToken so [Timeout] can cancel
        var result = await _fetcher.FetchAsync(
            "https://example.com", _testContext.CancellationToken);

        Assert.AreEqual("ok", result);
    }

    [TestMethod]
    public async Task FetchAsync_CancelledToken_ThrowsOperationCanceled()
    {
        using var cts = new CancellationTokenSource();
        cts.Cancel(); // pre-cancel

        await Assert.ThrowsExactlyAsync<TaskCanceledException>(
            async () => await _fetcher.FetchAsync("https://example.com", cts.Token));
    }

    // Minimal test double — swap out the HTTP pipeline without mocking frameworks
    private sealed class MockHttpMessageHandler : HttpMessageHandler
    {
        public HttpStatusCode StatusCode { get; set; } = HttpStatusCode.OK;
        public string ResponseContent { get; set; } = string.Empty;

        protected override Task<HttpResponseMessage> SendAsync(
            HttpRequestMessage request, CancellationToken cancellationToken)
        {
            cancellationToken.ThrowIfCancellationRequested();
            return Task.FromResult(new HttpResponseMessage(StatusCode)
            {
                Content = new StringContent(ResponseContent),
            });
        }
    }
}
```

**Key patterns demonstrated:**

| Pattern | How |
|---|---|
| **Async tests** | Return `async Task` — MSTest awaits them natively |
| **Timeouts** | `[Timeout(5000)]` + pass `_testContext.CancellationToken` into the code under test |
| **Cancellation** | Pre-cancel a `CancellationTokenSource`, assert `TaskCanceledException` |
| **Exception testing** | `Assert.ThrowsExactlyAsync<T>` instead of `[ExpectedException]` |
| **HttpClient testing** | Custom `HttpMessageHandler` — no mocking library needed |
| **Constructor injection** | `TestContext` injected via constructor (MSTest 3.6+), enables `readonly` fields |
| **Sealed test class** | `sealed` for performance and design clarity |
